1	import { useState, useEffect, useRef, useCallback } from "react";
2	import { useParams, useLocation } from "wouter";
3	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
4	import { apiRequest } from "@/lib/queryClient";
5	import { Button } from "@/components/ui/button";
6	import { Badge } from "@/components/ui/badge";
7	import { Input } from "@/components/ui/input";
8	import { Textarea } from "@/components/ui/textarea";
9	import { useToast } from "@/hooks/use-toast";
10	import {
11	  Mic, MicOff, Video, VideoOff, Square,
12	  Users, MessageSquare, Copy, Check, ArrowLeft, Radio,
13	  Link2, Info, ExternalLink, Monitor, MonitorOff,
14	  HelpCircle, BookOpen, Settings2, BarChart2, Clock,
15	  X, Send, CheckCircle, AlertCircle, Circle, Zap,
16	  BarChart3, Plus, Trash2, Hand,
17	} from "lucide-react";
18	import { format } from "date-fns";
19	
20	const GOLD = "#d4b461";
21	
22	const QUALITY_PRESETS = {
23	  "720p":  { width: 1280,  height: 720,  frameRate: 30, label: "720p HD",       badge: "HD"  },
24	  "1080p": { width: 1920,  height: 1080, frameRate: 30, label: "1080p Full HD", badge: "FHD" },
25	  "4k":    { width: 3840,  height: 2160, frameRate: 30, label: "4K Ultra HD",   badge: "4K"  },
26	};
27	type Quality = keyof typeof QUALITY_PRESETS;
28	
29	const ICE_SERVERS = [
30	  { urls: "stun:stun.l.google.com:19302" },
31	  { urls: "stun:stun1.l.google.com:19302" },
32	  { urls: "turn:openrelay.metered.ca:80",               username: "openrelayproject", credential: "openrelayproject" },
33	  { urls: "turn:openrelay.metered.ca:443",              username: "openrelayproject", credential: "openrelayproject" },
34	  { urls: "turn:openrelay.metered.ca:443?transport=tcp", username: "openrelayproject", credential: "openrelayproject" },
35	];
36	
37	function getEmbedUrl(url: string): string {
38	  if (!url) return "";
39	  const yt = url.match(/(?:youtube\.com\/watch\?v=|youtu\.be\/)([^&?/\s]+)/);
40	  if (yt) return `https://www.youtube.com/embed/${yt[1]}?autoplay=1&rel=0`;
41	  const vim = url.match(/vimeo\.com\/(\d+)/);
42	  if (vim) return `https://player.vimeo.com/video/${vim[1]}?autoplay=1`;
43	  return url;
44	}
45	
46	function isDirectVideo(url: string): boolean {
47	  return /\.(mp4|mov|webm|ogg|mkv)(\?.*)?$/i.test(url);
48	}
