50	function CopyBtn({ text }: { text: string }) {
51	  const [copied, setCopied] = useState(false);
52	  return (
53	    <button
54	      onClick={() => { navigator.clipboard.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
55	      className="text-zinc-400 hover:text-white transition-colors"
56	      title="Copy"
57	    >
58	      {copied ? <Check className="w-4 h-4 text-green-400" /> : <Copy className="w-4 h-4" />}
59	    </button>
60	  );
61	}
62	
63	
64	export default function WebinarStudio() {
65	  const params = useParams<{ id: string }>();
66	  const webinarId = params?.id;
67	  const [, nav] = useLocation();
68	  const qc = useQueryClient();
69	  const { toast } = useToast();
70	
71	  const videoRef   = useRef<HTMLVideoElement>(null);
72	  const pipRef     = useRef<HTMLVideoElement>(null);
73	  const camStream    = useRef<MediaStream | null>(null);
74	  const scrStream    = useRef<MediaStream | null>(null);
75	  const timerRef     = useRef<ReturnType<typeof setInterval> | null>(null);
76	  const chatEndRef   = useRef<HTMLDivElement>(null);
77	  const wsRef        = useRef<WebSocket | null>(null);
78	  const peerConnsRef = useRef<Map<string, RTCPeerConnection>>(new Map());
79	
80	  const [activeTab,     setActiveTab]     = useState<"chat"|"qa"|"attendees"|"notes"|"polls">("chat");
81	  const [showSettings,  setShowSettings]  = useState(false);
82	  const [cameraReady,   setCameraReady]   = useState(false);
83	  const [cameraError,   setCameraError]   = useState<string|null>(null);
84	  const [micOn,         setMicOn]         = useState(true);
85	  const [camOn,         setCamOn]         = useState(true);
86	  const [screenSharing, setScreenSharing] = useState(false);
87	  const [quality,       setQuality]       = useState<Quality>("1080p");
88	  const [cameras,       setCameras]       = useState<MediaDeviceInfo[]>([]);
89	  const [mics,          setMics]          = useState<MediaDeviceInfo[]>([]);
90	  const [selCam,        setSelCam]        = useState("");
91	  const [selMic,        setSelMic]        = useState("");
92	  const [elapsed,       setElapsed]       = useState(0);
93	  const [chatMsg,       setChatMsg]       = useState("");
94	  const [messages,      setMessages]      = useState<{name:string;text:string;ts:string;isHost?:boolean}[]>([
95	    { name: "System", text: "Studio ready. Start your camera to preview, then click Go Live.", ts: format(new Date(), "h:mm a") },
96	  ]);
97	  const [qaItems,      setQaItems]      = useState<{id:string;name:string;question:string;answered:boolean;ts:string}[]>([]);
98	  const [attendees,    setAttendees]    = useState<{id:string;name:string;raisedHand?:boolean}[]>([]);
99	  const [liveCount,    setLiveCount]    = useState(0);
100	  const [notes,        setNotes]        = useState("");
101	  const [floatReacts,  setFloatReacts]  = useState<{id:string;emoji:string;x:number}[]>([]);
102	  const [recording,    setRecording]    = useState(false);
103	  const [recordingMs,  setRecordingMs]  = useState(0);
104	  const [uploadingRec, setUploadingRec] = useState(false);
105	  const mediaRecorder   = useRef<MediaRecorder | null>(null);
106	  const recordChunks    = useRef<Blob[]>([]);
107	  const [ctaActive,     setCtaActive]     = useState(false);
108	  const [ctaTitle,      setCtaTitle]      = useState("");
109	  const [ctaUrl,        setCtaUrl]        = useState("");
110	  const [ctaButtonText, setCtaButtonText] = useState("Get Access Now →");
111	  const [showCtaPanel,  setShowCtaPanel]  = useState(false);
112	  const [ctaClickCount, setCtaClickCount] = useState(0);
113	  // ── Polls state ────────────────────────────────────────────────────────
114	  const [pollQuestion,  setPollQuestion]  = useState("");
115	  const [pollOptions,   setPollOptions]   = useState(["", ""]);
116	  const [activePollId,  setActivePollId]  = useState<string|null>(null);
117	  const [pollResults,   setPollResults]   = useState<Record<string, number[]>>({});
118	  const recordTimer     = useRef<ReturnType<typeof setInterval> | null>(null);
119	  const hostConnected   = useRef(false);
120	
121	  const { data: webinar, isLoading } = useQuery<any>({ queryKey: [`/api/webinars/${webinarId}`], enabled: !!webinarId });
122	  const { data: registrations = [] }  = useQuery<any[]>({ queryKey: [`/api/webinars/${webinarId}/registrations`], enabled: !!webinarId });
123	  const { data: polls = [], refetch: refetchPolls } = useQuery<any[]>({ queryKey: [`/api/webinars/${webinarId}/polls`], enabled: !!webinarId });
124	
125	  const createPollMut = useMutation({
126	    mutationFn: (data: any) => apiRequest("POST", `/api/webinars/${webinarId}/polls`, data),
127	    onSuccess: () => { refetchPolls(); setPollQuestion(""); setPollOptions(["", ""]); toast({ title: "Poll created!" }); },
128	  });
129	  const deletePollMut = useMutation({
130	    mutationFn: (pollId: string) => apiRequest("DELETE", `/api/webinars/${webinarId}/polls/${pollId}`),
131	    onSuccess: () => { refetchPolls(); },
132	  });
133	
134	  const addSys = (text: string) =>
135	    setMessages(m => [...m, { name: "System", text, ts: format(new Date(), "h:mm a") }]);
136	
137	  // ── Floating reaction helper ─────────────────────────────────────────────
138	  const addFloatReact = useCallback((emoji: string) => {
139	    const id = Math.random().toString(36).slice(2);
140	    const x = Math.random() * 60 + 10;
141	    setFloatReacts(r => [...r, { id, emoji, x }]);
142	    setTimeout(() => setFloatReacts(r => r.filter(rx => rx.id !== id)), 2300);
143	  }, []);
144	
145	  // ── WebRTC broadcasting ──────────────────────────────────────────────────
146	  const connectHost = useCallback(() => {
147	    if (!webinarId) return;
148	    const wsUrl = `${window.location.protocol === "https:" ? "wss:" : "ws:"}//${window.location.host}/ws`;
149	    const ws = new WebSocket(wsUrl);
150	    wsRef.current = ws;
151	
152	    const doCreatePeer = async (viewerId: string) => {
153	      const videoStream = scrStream.current || camStream.current;
154	      const audioStream = camStream.current || scrStream.current;
155	      if (!videoStream) { addSys("A viewer joined but no active stream — start your camera first."); return; }
156	
157	      const pc = new RTCPeerConnection({ iceServers: ICE_SERVERS });
158	      peerConnsRef.current.set(viewerId, pc);
159	      videoStream.getVideoTracks().forEach(t => pc.addTrack(t, videoStream));
160	      audioStream?.getAudioTracks().forEach(t => pc.addTrack(t, audioStream));
161	
162	      pc.onicecandidate = (evt) => {
163	        if (evt.candidate && ws.readyState === WebSocket.OPEN)
164	          ws.send(JSON.stringify({ type: "wr_ice_host", webinarId, viewerId, candidate: evt.candidate }));
165	      };
166	
167	      const offer = await pc.createOffer();
168	      await pc.setLocalDescription(offer);
169	      if (ws.readyState === WebSocket.OPEN)
170	        ws.send(JSON.stringify({ type: "wr_offer", webinarId, viewerId, sdp: pc.localDescription }));
171	    };
172	
173	    ws.onopen = () => ws.send(JSON.stringify({ type: "wr_host_join", webinarId }));
174	
175	    ws.onmessage = async (e) => {
176	      try {
177	        const msg = JSON.parse(e.data);
178	        switch (msg.type) {
179	          case "wr_host_ready":
180	            addSys("Broadcasting ready — share your watch link so attendees can join.");
181	            break;
182	          case "wr_viewer_joined": {
183	            await doCreatePeer(msg.viewerId);
184	            addSys(`${msg.name || "A viewer"} joined the live stream.`);
185	            break;
186	          }
187	          case "wr_answer": {
188	            const pc = peerConnsRef.current.get(msg.viewerId);
189	            if (pc) await pc.setRemoteDescription(new RTCSessionDescription(msg.sdp)).catch(() => {});
190	            break;
191	          }
192	          case "wr_ice": {
193	            const pc = peerConnsRef.current.get(msg.viewerId);
194	            if (pc && msg.candidate)
195	              await pc.addIceCandidate(new RTCIceCandidate(msg.candidate)).catch(() => {});
196	            break;
197	          }
198	          case "wr_viewer_left": {
199	            const pc = peerConnsRef.current.get(msg.viewerId);
200	            pc?.close();
201	            peerConnsRef.current.delete(msg.viewerId);
202	            break;
203	          }
204	          case "wr_chat":
205	            setMessages(m => [...m, msg.message]);
206	            break;
207	          case "wr_qa":
208	            setQaItems(q => [...q, { id: msg.question.id, name: msg.question.name, question: msg.question.text, answered: false, ts: msg.question.ts }]);
209	            break;
210	          case "wr_reaction":
211	            addFloatReact(msg.emoji);
212	            break;
213	          case "wr_raise_hand":
214	            addSys(`✋ ${msg.name} raised their hand.`);
215	            break;
216	          case "wr_attendee_update":
217	            setLiveCount(msg.count);
218	            setAttendees(msg.list || []);
219	            break;
220	          case "wr_cta_clicked":
221	            setCtaClickCount(c => c + 1);
222	            break;
223	          case "wr_poll_results":
224	            setPollResults(r => ({ ...r, [msg.pollId]: msg.votes }));
225	            break;
226	          case "wr_poll_ended":
227	            setActivePollId(null);
228	            setPollResults(r => ({ ...r, [msg.pollId]: msg.votes }));
229	            break;
230	        }
231	      } catch {}
232	    };
233	  }, [webinarId, addFloatReact]);
234	
235	  const startMut = useMutation({
236	    mutationFn: () => apiRequest("POST", `/api/webinars/${webinarId}/start`),
237	    onSuccess: () => {
238	      qc.invalidateQueries({ queryKey: [`/api/webinars/${webinarId}`] });
239	      toast({ title: "🔴 You are now LIVE!" });
240	      timerRef.current = setInterval(() => setElapsed(e => e + 1), 1000);
241	      addSys("Webinar started — attendees can now join!");
242	      hostConnected.current = true;
243	      connectHost();
244	    },
245	  });
246	  const endMut = useMutation({
247	    mutationFn: () => apiRequest("POST", `/api/webinars/${webinarId}/end`),
248	    onSuccess: () => {
249	      qc.invalidateQueries({ queryKey: [`/api/webinars/${webinarId}`] });
250	      toast({ title: "Webinar ended." });
251	      if (timerRef.current) clearInterval(timerRef.current);
252	      if (mediaRecorder.current?.state !== "inactive") { mediaRecorder.current?.stop(); setRecording(false); if (recordTimer.current) { clearInterval(recordTimer.current); recordTimer.current = null; } }
253	      if (wsRef.current?.readyState === WebSocket.OPEN)
254	        wsRef.current.send(JSON.stringify({ type: "wr_host_end", webinarId }));
255	      wsRef.current?.close();
256	      peerConnsRef.current.forEach(pc => pc.close());
257	      peerConnsRef.current.clear();
258	      addSys("Webinar has ended. Viewers have been notified.");
259	    },
260	  });
261	
262	  const fmtElapsed = (s: number) => {
263	    const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), sec = s % 60;
264	    return h > 0
265	      ? `${h}:${String(m).padStart(2,"0")}:${String(sec).padStart(2,"0")}`
266	      : `${String(m).padStart(2,"0")}:${String(sec).padStart(2,"0")}`;
267	  };
268	
269	  const enumDevices = useCallback(async () => {
270	    try {
271	      const devs = await navigator.mediaDevices.enumerateDevices();
272	      const cams = devs.filter(d => d.kind === "videoinput");
273	      const micsF = devs.filter(d => d.kind === "audioinput");
