1	import { useState, useRef, useCallback } from "react";
2	import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
3	import { apiRequest } from "@/lib/queryClient";
4	import { Button } from "@/components/ui/button";
5	import { Input } from "@/components/ui/input";
6	import { Textarea } from "@/components/ui/textarea";
7	import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
8	import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
9	import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
10	import { Label } from "@/components/ui/label";
11	import { useToast } from "@/hooks/use-toast";
12	import {
13	  Upload, Video, Link2, Play, Trash2, Eye, Clock, TrendingUp,
14	  Plus, Activity, Target, BarChart3, Code2, Lock, Unlock, Copy,
15	  Check, Film, Zap, Shield, Timer, MousePointer, Hash, ChevronDown,
16	  RefreshCw, Settings2, ExternalLink, AlertCircle, Layers,
17	} from "lucide-react";
18	import { format } from "date-fns";
19	
20	const GOLD = "#d4b461";
21	
22	const PROGRESS_BAR_PRESETS = [
23	  { id: "slow-start", name: "Slow Start", desc: "Starts slow (20%), then speeds up", segments: "0-25%: 40s, 25-50%: 20s, 50-75%: 15s, 75-100%: 10s" },
24	  { id: "steady",     name: "Steady Progress", desc: "Consistent speed throughout", segments: "0-100%: Even pace" },
25	  { id: "fast-start", name: "Fast Start", desc: "Starts fast, then slows down", segments: "0-25%: 10s, 25-50%: 15s, 50-75%: 20s, 75-100%: 30s" },
26	  { id: "custom",     name: "Custom Segments", desc: "Define your own timing", segments: "Custom" },
27	];
28	
29	function EmbedDialog({ video, onClose }: { video: any; onClose: () => void }) {
30	  const [copied, setCopied] = useState(false);
31	  const baseUrl = typeof window !== "undefined" ? window.location.origin : "";
32	  const iframeCode = `<iframe src="${baseUrl}/watch-video/${video.id}" width="100%" height="480" frameborder="0" allowfullscreen style="border-radius:12px;"></iframe>`;
33	  const directUrl = `${baseUrl}/watch-video/${video.id}`;
34	
35	  const copy = (text: string) => {
36	    navigator.clipboard.writeText(text);
37	    setCopied(true);
38	    setTimeout(() => setCopied(false), 2000);
39	  };
40	
41	  return (
42	    <Dialog open onOpenChange={onClose}>
43	      <DialogContent className="bg-zinc-900 border-zinc-700 max-w-lg">
44	        <DialogHeader>
45	          <DialogTitle className="text-white font-bold flex items-center gap-2">
46	            <Code2 className="w-4 h-4" style={{ color: GOLD }} /> Embed: {video.title}
47	          </DialogTitle>
48	        </DialogHeader>
49	        <div className="space-y-4 py-2">
50	          <div>
51	            <Label className="text-xs text-zinc-400 mb-2 block">Embed Code (iframe)</Label>
52	            <div className="relative">
53	              <pre className="text-xs text-zinc-300 bg-zinc-800 rounded-lg p-3 overflow-x-auto whitespace-pre-wrap break-all border border-zinc-700">{iframeCode}</pre>
54	              <button onClick={() => copy(iframeCode)} className="absolute top-2 right-2 p-1.5 rounded-lg hover:bg-zinc-700 transition-colors">
55	                {copied ? <Check className="w-3.5 h-3.5 text-green-400" /> : <Copy className="w-3.5 h-3.5 text-zinc-400" />}
56	              </button>
57	            </div>
58	          </div>
59	          <div>
60	            <Label className="text-xs text-zinc-400 mb-2 block">Direct Player URL</Label>
