446	              <Textarea placeholder="What is this video about?" value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} className="bg-zinc-800 border-zinc-700 text-white resize-none" rows={2} />
447	            </div>
448	
449	            {form.videoType === "vsl" && (
450	              <div className="border border-zinc-800 rounded-xl p-4 space-y-4" style={{ background: "rgba(167,139,250,0.04)", borderColor: "#a78bfa30" }}>
451	                <div className="flex items-center gap-2">
452	                  <Zap className="w-4 h-4" style={{ color: "#a78bfa" }} />
453	                  <span className="text-sm font-bold text-white">VSL Settings</span>
454	                </div>
455	                <div className="flex items-center justify-between">
456	                  <div>
457	                    <Label className="text-sm font-semibold text-zinc-300">Progress Bar Manipulation</Label>
458	                    <p className="text-xs text-zinc-500 mt-0.5">Control how fast/slow the progress bar moves to improve watch time</p>
459	                  </div>
