461	                </div>
462	                {form.progressBarEnabled && (
463	                  <div className="space-y-2">
464	                    {PROGRESS_BAR_PRESETS.map((preset) => (
465	                      <div key={preset.id} onClick={() => setForm({ ...form, progressBarStyle: preset.id })}
466	                        className="p-3 rounded-lg border cursor-pointer transition-all" style={{
467	                          background: form.progressBarStyle === preset.id ? "rgba(167,139,250,0.12)" : "rgba(255,255,255,0.03)",
468	                          borderColor: form.progressBarStyle === preset.id ? "#a78bfa55" : "rgba(63,63,70,0.5)",
469	                        }}>
470	                        <div className="flex items-center justify-between mb-0.5">
471	                          <p className="text-xs font-semibold text-white">{preset.name}</p>
472	                          {form.progressBarStyle === preset.id && <div className="w-3 h-3 rounded-full bg-purple-400" />}
473	                        </div>
474	                        <p className="text-[10px] text-zinc-500">{preset.desc}</p>
475	                      </div>
476	                    ))}
477	                    {form.progressBarStyle === "custom" && (
478	                      <Textarea placeholder="e.g. 0-20%: 30s, 20-50%: 20s, 50-100%: 15s" value={form.customProgressSegments} onChange={(e) => setForm({ ...form, customProgressSegments: e.target.value })} className="bg-zinc-800 border-zinc-700 text-white resize-none font-mono text-xs mt-2" rows={3} />
479	                    )}
