487	              <Input placeholder="https://..." value={form.thumbnailUrl} onChange={(e) => setForm({ ...form, thumbnailUrl: e.target.value })} className="bg-zinc-800 border-zinc-700 text-white" />
488	            </div>
489	          </div>
490	
491	          <DialogFooter>
492	            <Button variant="ghost" onClick={() => setShowCreate(false)} className="text-zinc-400">Cancel</Button>
493	            <Button onClick={handleCreate} disabled={createMut.isPending || !form.title || !form.videoUrl} style={{ background: GOLD, color: "#000" }} className="font-semibold">
494	              {createMut.isPending ? "Adding…" : "Add Video"}
495	            </Button>
496	          </DialogFooter>
497	        </DialogContent>
498	      </Dialog>
499	    </div>
500	  );
501	}
