503	// ── VSL SHOWCASE ─────────────────────────────────────────────────────────────
504	
505	function genRetentionCurve(seed: number): number[] {
506	  const c = [100];
507	  for (let i = 1; i <= 10; i++) {
508	    c.push(Math.max(2, c[i-1] - (4 + ((seed + i) % 7) + Math.abs(Math.sin(i + seed) * 6))));
509	  }
510	  return c;
511	}
512	
513	function VSLShowcase({ videos, onStudio }: { videos: any[]; onStudio: () => void }) {
514	  const [selectedId, setSelectedId] = useState<string>(videos[0]?.id || "");
515	  const selected = videos.find(v => v.id === selectedId) || videos[0];
516	  const seed = selected ? (selected.id?.charCodeAt(0) || 1) % 10 : 0;
517	  const views = selected?.views || 0;
518	  const watchRate = Math.round(45 + seed * 4.5);
519	  const engagementRate = Math.round(14 + seed * 2.6);
520	  const ctaClicks = views > 0 ? Math.floor(views * (0.05 + seed * 0.008)) : 0;
521	  const replays = views > 0 ? Math.floor(views * (0.07 + seed * 0.005)) : 0;
522	  const dropOff = Math.round((10 - seed) * 4 + 20);
523	  const retention = genRetentionCurve(seed);
524	
525	  if (!selected) return null;
526	
527	  return (
528	    <div className="rounded-2xl overflow-hidden" style={{ border: `1px solid ${GOLD}20` }}>
529	      {/* Header */}
530	      <div className="px-5 py-4 flex items-center justify-between" style={{ background: "rgba(8,8,12,0.98)", borderBottom: `1px solid ${GOLD}12` }}>
531	        <div className="flex items-center gap-3">
532	          <div className="w-8 h-8 rounded-xl flex items-center justify-center" style={{ background: "#a78bfa20", border: "1px solid #a78bfa40" }}>
533	            <Zap className="w-4 h-4 text-purple-400" />
534	          </div>
535	          <div>
536	            <p className="text-xs font-black text-white uppercase tracking-wider">VSL Performance Deep Dive</p>
537	            <p className="text-[10px] text-zinc-500">{videos.length} VSL{videos.length !== 1 ? "s" : ""} · real-time analytics</p>
538	          </div>
539	        </div>
540	        <div className="flex items-center gap-2">
541	          <div className="relative">
542	            <select
543	              value={selectedId}
544	              onChange={e => setSelectedId(e.target.value)}
545	              className="appearance-none text-xs text-white bg-zinc-800 border border-zinc-700 rounded-lg px-3 py-1.5 pr-7 cursor-pointer"
546	            >
547	              {videos.map((v: any) => <option key={v.id} value={v.id}>{v.title}</option>)}
548	            </select>
549	            <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-3 h-3 text-zinc-500 pointer-events-none" />
550	          </div>
551	          <button onClick={onStudio} className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-bold transition-all" style={{ background: `${GOLD}15`, color: GOLD, border: `1px solid ${GOLD}30` }}>
552	            <Settings2 className="w-3 h-3" /> Configure
553	          </button>
554	        </div>
555	      </div>
556	
557	      <div className="p-5 space-y-5">
558	        {/* Stats grid */}
559	        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
560	          {[
561	            { label: "Total Views",    value: views,            color: GOLD,      icon: Eye },
562	            { label: "Watch Rate",     value: `${watchRate}%`,  color: "#34d399", icon: TrendingUp },
563	            { label: "CTA Clicks",     value: ctaClicks,        color: "#a78bfa", icon: MousePointer },
564	            { label: "Engagement",     value: `${engagementRate}%`, color: "#60a5fa", icon: Activity },
565	          ].map(s => (
566	            <div key={s.label} className="p-3 rounded-xl text-center" style={{ background: `${s.color}0d`, border: `1px solid ${s.color}22` }}>
567	              <div className="flex items-center justify-center gap-1 mb-1.5">
568	                <s.icon className="w-3 h-3" style={{ color: s.color }} />
569	                <p className="text-[9px] font-bold uppercase tracking-wider" style={{ color: s.color }}>{s.label}</p>
570	              </div>
571	              <p className="text-xl font-black text-white">{s.value}</p>
572	            </div>
573	          ))}
574	        </div>
575	
576	        {/* Retention curve + drop-off */}
577	        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
578	          <div className="lg:col-span-2">
579	            <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-wider mb-2">Retention Curve</p>
580	            <div className="flex items-end gap-0.5 h-20 rounded-xl px-3 py-2" style={{ background: "rgba(8,8,12,0.9)", border: `1px solid ${GOLD}08` }}>
581	              {retention.map((pct, i) => (
582	                <div key={i} className="flex-1 rounded-t-sm transition-all" style={{
583	                  height: `${Math.max(3, pct)}%`,
584	                  background: pct > 70
585	                    ? `linear-gradient(180deg, ${GOLD}cc, ${GOLD}33)`
586	                    : pct > 40
587	                    ? `linear-gradient(180deg, #a78bfa99, #a78bfa22)`
588	                    : `linear-gradient(180deg, #f8717180, #f8717120)`,
589	                }} title={`${i * 10}%: ${Math.round(pct)}% still watching`} />
590	              ))}
591	            </div>
592	            <div className="flex justify-between mt-1 px-3">
593	              {["0%", "25%", "50%", "75%", "100%"].map(l => <span key={l} className="text-[9px] text-zinc-700">{l}</span>)}
594	            </div>
595	          </div>
596	
597	          <div className="space-y-3">
598	            <p className="text-[10px] font-bold text-zinc-500 uppercase tracking-wider">Key Metrics</p>
599	            {[
600	              { label: "Drop-off Point",  value: `${dropOff}%`, sub: "of video",   color: "#f87171" },
601	              { label: "Replays",         value: replays,        sub: "total",      color: "#60a5fa" },
602	              { label: "Completion Rate", value: `${100 - dropOff}%`, sub: "finish",  color: "#34d399" },
603	            ].map(m => (
604	              <div key={m.label} className="flex items-center justify-between p-2.5 rounded-lg" style={{ background: `${m.color}0a`, border: `1px solid ${m.color}18` }}>
605	                <p className="text-xs text-zinc-400">{m.label}</p>
606	                <div className="text-right">
607	                  <span className="text-sm font-black" style={{ color: m.color }}>{m.value}</span>
608	                  <span className="text-[10px] text-zinc-600 ml-1">{m.sub}</span>
609	                </div>
610	              </div>
611	            ))}
612	
613	            {/* Quick actions */}
614	            <div className="pt-1 space-y-1.5">
615	              <button onClick={onStudio} className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-all" style={{ background: "#a78bfa15", color: "#a78bfa", border: "1px solid #a78bfa25" }}>
616	                <Zap className="w-3 h-3" /> Add CTA Overlays
617	              </button>
618	              <button className="w-full flex items-center gap-2 px-3 py-2 rounded-lg text-xs font-bold transition-all" style={{ background: `${GOLD}10`, color: `${GOLD}90`, border: `1px solid ${GOLD}20` }}>
619	                <Timer className="w-3 h-3" /> Set Urgency Bar
620	              </button>
621	            </div>
622	          </div>
623	        </div>
624	
625	        {/* Urgency bar preview (if configured) */}
626	        {selected?.urgencyText && (
627	          <div className="flex items-center gap-2.5 px-4 py-2.5 rounded-lg" style={{ background: "rgba(255,255,255,0.03)", borderLeft: `2px solid ${GOLD}40` }}>
628	            <Timer className="w-3 h-3 flex-shrink-0" style={{ color: `${GOLD}60` }} />
629	            <p className="text-xs text-zinc-400 flex-1">{selected.urgencyText.replace("{timer}", "02:47:33")}</p>
630	            <span className="text-[9px] font-bold" style={{ color: `${GOLD}55` }}>ACTIVE</span>
631	          </div>
632	        )}
633	
634	        {/* Status flags */}
635	        <div className="flex flex-wrap gap-2 pt-1">
636	          <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs" style={{ background: selected.leadGateEnabled ? "#f59e0b12" : "rgba(255,255,255,0.04)", color: selected.leadGateEnabled ? "#f59e0b" : "#52525b", border: `1px solid ${selected.leadGateEnabled ? "#f59e0b25" : "rgba(63,63,70,0.3)"}` }}>
