638	          </div>
639	          <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs" style={{ background: selected.brandColor ? `${selected.brandColor}12` : "rgba(255,255,255,0.04)", color: selected.brandColor ? selected.brandColor : "#52525b", border: `1px solid ${selected.brandColor ? selected.brandColor + "25" : "rgba(63,63,70,0.3)"}` }}>
640	            <div className="w-2.5 h-2.5 rounded-full" style={{ background: selected.brandColor || "#52525b" }} />
641	            Branded Player {selected.brandColor ? "✓" : "—"}
